class Solution(object):
    def maxSubstrings(self, word):
        n = len(word)
        first_occ = {}  # char -> first unused occurrence index
        # dp[i] = max substrings using characters in word[0..i-1]
        # Greedy: for each i, check if word[first[c]..i] is valid (length >= 4)
        dp = [0] * (n + 1)
        for i in range(n):
            c = word[i]
            dp[i+1] = dp[i]
            if c in first_occ:
                j = first_occ[c]
                if i - j + 1 >= 4:
                    # Take substring [j..i]
                    dp[i+1] = max(dp[i+1], dp[j] + 1)
                    # Update first occurrence to look for next one
                    del first_occ[c]
            if c not in first_occ:
                first_occ[c] = i
        return dp[n]
